#include <iostream>
using namespace std;
int contor = 0;
void f(int n) {
    contor++;
    if (n > 0) f(n-1);
}
int main() {
    f(4);
    cout << contor;
    return 0;
}

#include <iostream>
using namespace std;
int main() {
    int v[8] = {0,-2,1,-3,4,-1,2,1};
    int n = 7, mx = v[1], s = v[1];
    for (int i = 2; i <= n; i++) {
        if (s < 0) s = v[i];
        else s += v[i];
        if (s > mx) mx = s;
    }
    cout << mx;
    return 0;
}
